import{c as o,Q as d,j as e,m as a}from"./chunks/framework.Bhbi9jCp.js";const m=JSON.parse('{"title":"mod 架构:Fabric、Forge 与 Mixin","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/24-mod架构-Fabric-Forge与Mixin.md","filePath":"minecraftLearning/24-mod架构-Fabric-Forge与Mixin.md","lastUpdated":1781677803000}'),r={name:"minecraftLearning/24-mod架构-Fabric-Forge与Mixin.md"};function n(i,t,s,c,p,l){return d(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="mod-架构-fabric、forge-与-mixin" tabindex="-1">mod 架构:Fabric、Forge 与 Mixin <a class="header-anchor" href="#mod-架构-fabric、forge-与-mixin" aria-label="Permalink to &quot;mod 架构:Fabric、Forge 与 Mixin&quot;">​</a></h1><p>先说一个很多人没意识到的事实:<strong>Minecraft Java 版从来没有官方 mod API。</strong> Mojang 没开放任何&quot;插件接口&quot;,游戏发布出来就是一个混淆过的、自洽的 jar。那几万个 mod 是怎么来的?答案不太体面但很硬核——<strong>社区是在运行时把游戏的代码改写了</strong>。整个 mod 生态,本质是一群人在没有任何官方扩展点的前提下,用字节码工程硬生生造出来的一层。</p><blockquote><p>一句话先记住:<strong>modloader 是一个在游戏启动前接管类加载的引导层,Mixin 是往别人编译好的方法里插桩的手术刀,mappings 是把混淆代码翻译回人话的字典——三者合起来,才让&quot;改一个闭源游戏&quot;变得可工程化。</strong></p></blockquote><hr><h2 id="一、没有-api-怎么改-——modloader-接管类加载" tabindex="-1">一、没有 API,怎么改?——modloader 接管类加载 <a class="header-anchor" href="#一、没有-api-怎么改-——modloader-接管类加载" aria-label="Permalink to &quot;一、没有 API,怎么改?——modloader 接管类加载&quot;">​</a></h2><p>普通程序加载类很直接:JVM 从 jar 里读 <code>.class</code> 字节,丢给类加载器,执行。modloader 做的事,就是<strong>在这条链路中间插一脚</strong>。</p><p>它本质是一个<strong>引导器(bootstrap)</strong>:在原版游戏的任何一个类被真正加载之前,先由 modloader 启动,接管类加载器,然后做两件事:</p><ol><li><strong>扫描 mods 文件夹</strong>,把每个 mod 的入口注册进来;</li><li><strong>在类字节被交给 JVM 之前,允许 mod 对它做改写</strong>(下面 Mixin 那节展开)。</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>正常:  jar 字节 ──────────────► JVM 加载 ──► 运行原版逻辑</span></span>
<span class="line"><span></span></span>
<span class="line"><span>有 mod:jar 字节 ──► modloader 拦截 ──► 应用 mod 的字节码改写 ──► JVM 加载 ──► 运行被改过的逻辑</span></span>
<span class="line"><span>                         ▲</span></span>
<span class="line"><span>                      mods/*.jar 在这里插手</span></span></code></pre></div><p>所以&quot;装 mod&quot;不是&quot;游戏调用了插件&quot;,而是<strong>游戏自己的代码在加载瞬间被动过手脚</strong>。这个区别决定了后面所有的痛苦与威力:威力是你几乎能改任何东西;痛苦是你改的是私有实现,版本一变就崩。</p><hr><h2 id="二、三大加载器-fabric-forge-neoforge" tabindex="-1">二、三大加载器:Fabric / Forge / NeoForge <a class="header-anchor" href="#二、三大加载器-fabric-forge-neoforge" aria-label="Permalink to &quot;二、三大加载器:Fabric / Forge / NeoForge&quot;">​</a></h2><p>不存在唯一的 modloader,生态分裂成几支,取舍各不相同。</p><table tabindex="0"><thead><tr><th></th><th>Fabric</th><th>Forge</th><th>NeoForge</th></tr></thead><tbody><tr><td>定位</td><td>轻量、最小内核</td><td>重量级、自带全套 API</td><td>Forge 的社区分支</td></tr><tr><td>跟版速度</td><td>快(新版本几天内可用)</td><td>慢(API 大,适配久)</td><td>中</td></tr><tr><td>自带 API</td><td>几乎没有,功能靠 Fabric API 模块按需加</td><td>大而全(事件总线、能力系统、注册封装……)</td><td>继承 Forge 并持续重构</td></tr><tr><td>适合</td><td>小而快的 mod、性能优化 mod、跟最新版</td><td>大型整合包、内容向 mod</td><td>Forge 路线的现代延续</td></tr><tr><td>入口机制</td><td><code>fabric.mod.json</code> 声明 entrypoint</td><td><code>@Mod</code> 注解 + 事件总线</td><td>类 Forge</td></tr></tbody></table><p>几个要点:</p><ul><li><strong>Fabric 的哲学是&quot;内核最小&quot;</strong>:加载器本身几乎只做引导和 Mixin 集成,连&quot;注册方块&quot;这种事都得引入 Fabric API 这个独立 mod。所以它轻、跟版快——这也是 Lithium、Sodium、Starlight 这类性能 mod 多在 Fabric 上的原因(它们要的就是贴近原版、快速适配)。</li><li><strong>Forge 的哲学是&quot;大而全&quot;</strong>:提供事件总线、能力(capability)、统一的注册和配置体系,内容向大 mod 写起来省事,代价是包重、跟版慢。</li><li><strong>NeoForge</strong> 是 2023 年从 Forge 分出来的社区分支,因为治理与技术路线分歧,如今很多新内容 mod 转向它。</li></ul><p><strong>entrypoint(入口点)</strong> 是各家共有的概念:mod 不是&quot;被 new 出来&quot;,而是在元数据里声明&quot;我的初始化逻辑在哪个类/方法&quot;,加载器在合适的生命周期阶段去调它。Fabric 区分 <code>main</code>/<code>client</code>/<code>server</code> 等入口,对应不同环境;Forge 用 <code>@Mod</code> 标注主类并通过事件回调挂载逻辑。</p><hr><h2 id="三、混淆与映射-为什么-mod-死死绑版本" tabindex="-1">三、混淆与映射:为什么 mod 死死绑版本 <a class="header-anchor" href="#三、混淆与映射-为什么-mod-死死绑版本" aria-label="Permalink to &quot;三、混淆与映射:为什么 mod 死死绑版本&quot;">​</a></h2><p>这是理解 mod 生态脆弱性的关键,也是新手最容易忽略的一层。</p><p>Mojang <strong>发布的是混淆(obfuscated)过的代码</strong>:类名、方法名、字段名被替换成 <code>a</code>、<code>b</code>、<code>c</code>、<code>aabb</code> 这种无意义短名。原因是体积和一点点防护。问题是——你要给 <code>EntityPlayer.attack()</code> 注入逻辑,但在发布版里它可能叫 <code>class_1657.method_7324()</code>,甚至每个版本的混淆名都不一样。</p><p>于是有了 <strong>mappings(映射表)</strong>:一张把混淆名翻译回可读名的字典。</p><table tabindex="0"><thead><tr><th>映射</th><th>阵营</th><th>风格</th></tr></thead><tbody><tr><td><strong>Mojmap</strong>(官方 official mappings)</td><td>Mojang 自 1.14.4 起放出</td><td>官方名,权威但许可受限,近年成主流</td></tr><tr><td><strong>Yarn</strong></td><td>Fabric 社区</td><td>社区命名,开放,曾是 Fabric 默认</td></tr><tr><td><strong>MCP / SRG</strong></td><td>早期 Forge</td><td>历史映射体系,现已被取代</td></tr></tbody></table><p>开发时 mod 用可读名写代码;构建时再<strong>重映射(remap)</strong> 回目标版本的混淆名,才能和真实游戏对上。</p><p><strong>这就是 mod 强版本绑定的根源之一:</strong> 混淆名随版本变,映射也随版本变,你针对 1.20.1 编译的 mod,里面写死的是 1.20.1 的混淆引用,拿到 1.21 直接对不上号——哪怕逻辑一行没改。</p><hr><h2 id="四、mixin-往别人的方法里插桩" tabindex="-1">四、Mixin:往别人的方法里插桩 <a class="header-anchor" href="#四、mixin-往别人的方法里插桩" aria-label="Permalink to &quot;四、Mixin:往别人的方法里插桩&quot;">​</a></h2><p>光接管类加载还不够,你得有手段<strong>精确地改原版方法的内部</strong>。这就是 Mixin——一个基于字节码注入的框架,现在是 Fabric 和 NeoForge 的事实标准(Forge 也支持)。</p><p>Mixin 的思路:你写一个&quot;mixin 类&quot;,用注解声明&quot;我要嫁接到哪个目标类的哪个方法的哪个位置&quot;,加载时框架把你的字节码<strong>织入(weave)</strong> 进目标方法。常用注解:</p><table tabindex="0"><thead><tr><th>注解</th><th>干什么</th></tr></thead><tbody><tr><td><code>@Inject</code></td><td>在方法的某个位置(开头/返回前/某次调用处)插入你的代码,可 <code>cancellable</code> 提前返回</td></tr><tr><td><code>@Redirect</code></td><td>把方法里的某个调用&quot;改道&quot;到你的实现</td></tr><tr><td><code>@ModifyVariable</code> / <code>@ModifyArg</code> / <code>@ModifyConstant</code></td><td>篡改方法里的局部变量、参数、常量</td></tr><tr><td><code>@Overwrite</code></td><td>整个替换目标方法(最暴力,最易冲突,尽量别用)</td></tr></tbody></table><p>注入点用 <code>@At</code> 描述,比如 <code>@At(&quot;HEAD&quot;)</code>(方法开头)、<code>@At(&quot;RETURN&quot;)</code>(返回前)、<code>@At(&quot;INVOKE&quot;, target=...)</code>(某个调用处)。</p><p>还有配套的开私有的手段:</p><ul><li><strong>Access Widener(Fabric)/ Access Transformer(Forge)</strong>:原版很多成员是 <code>private</code>/<code>final</code>,你正常碰不到。这两个机制在加载时<strong>放宽访问修饰符</strong>,把私有字段变可访问、去掉 <code>final</code>,好让你的 mixin 能动它们。</li></ul><h3 id="为什么多个-mod-改同一处会冲突" tabindex="-1">为什么多个 mod 改同一处会冲突 <a class="header-anchor" href="#为什么多个-mod-改同一处会冲突" aria-label="Permalink to &quot;为什么多个 mod 改同一处会冲突&quot;">​</a></h3><p>Mixin 强大,但它<strong>改的是共享的字节码</strong>。两个 mod 都 <code>@Redirect</code> 同一行调用,或都 <code>@Overwrite</code> 同一个方法,就会撞车——织入顺序、互相覆盖,结果不可预测。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原版方法 foo() {</span></span>
<span class="line"><span>   ... 调用 bar() ...     ◄── modA 想 @Redirect 这次调用</span></span>
<span class="line"><span>   ... 调用 bar() ...     ◄── modB 也想 @Redirect 同一次调用</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>两个 @Redirect 落在同一目标 → 冲突,轻则一方失效,重则崩</span></span></code></pre></div><p>这也是为什么整合包出问题时排查那么痛苦:崩溃栈里全是被织入的、不属于任何单一 mod 的&quot;缝合方法&quot;。<code>@Inject</code> 这种&quot;加在旁边&quot;的方式天然比 <code>@Overwrite</code> 这种&quot;整个换掉&quot;的兼容性好得多——好的 mod 作者会刻意用最轻的注入方式,就是为了少抢地盘。</p><hr><h2 id="五、版本脆弱性-为什么升级-mod-这么难" tabindex="-1">五、版本脆弱性:为什么升级 mod 这么难 <a class="header-anchor" href="#五、版本脆弱性-为什么升级-mod-这么难" aria-label="Permalink to &quot;五、版本脆弱性:为什么升级 mod 这么难&quot;">​</a></h2><p>把前面几篇的点串起来看,你会发现 mod 卡在好几条会随版本漂移的线上,任何一条变了都可能让它失效:</p><table tabindex="0"><thead><tr><th>漂移的东西</th><th>影响</th><th>关联</th></tr></thead><tbody><tr><td>混淆名 / 映射</td><td>方法字段引用全对不上,要重映射重编译</td><td>本篇第三节</td></tr><tr><td>目标方法的内部结构</td><td>mixin 注入点(某次调用、某个变量)可能不存在了,织入失败</td><td>本篇第四节</td></tr><tr><td>注册表条目增删改名</td><td>mod 注册的方块/物品 ID、与原版交互的 registry 假设可能失效;联机还要过 registry sync</td><td>见&quot;注册表、维度与修饰层&quot;一篇</td></tr><tr><td>存档结构</td><td>原版用 DataFixerUpper 迁移,但 mod 自己加的数据没人替你迁,跨版本存档容易坏</td><td>见&quot;数据组件与 DataFixerUpper&quot;一篇</td></tr></tbody></table><p>所以&quot;Minecraft mod 升级一个大版本要等几个月&quot;不是作者懒,而是<strong>他依赖的每一层地基都在动</strong>:映射变了、目标代码变了、注册和存档语义也可能变了。Fabric 之所以跟版快,正是因为它内核小、对原版内部结构的假设少;Forge 之所以慢,是因为它那套大 API 本身就深度绑定原版实现,牵一发动全身。</p><hr><h2 id="收一句" tabindex="-1">收一句 <a class="header-anchor" href="#收一句" aria-label="Permalink to &quot;收一句&quot;">​</a></h2><p>Minecraft 的 mod 生态是个很特别的工程样本:<strong>在一个完全没有官方扩展点、还故意混淆过的闭源游戏上,社区靠&quot;接管类加载 + 字节码注入 + 逆向映射&quot;三件套,硬造出了一个能装上万个扩展的平台。</strong></p><p>它的威力来自&quot;几乎能改任何东西&quot;,它的脆弱也来自同一件事——你改的不是稳定的 API,而是别人随时会变的私有实现。理解了这点,就理解了为什么 mod 那么强、又那么容易碎:<strong>这层扩展能力从来不是设计出来的,是工程出来的。</strong></p>`,46)])])}const h=o(r,[["render",n]]);export{m as __pageData,h as default};
